class Solution:
    def smallestTrimmedNumbers(self, nums, queries):
        ans = []
        for k, t in queries:
            order = sorted(range(len(nums)), key=lambda i: (nums[i][-t:], i))
            ans.append(order[k - 1])
        return ans

