class Solution:
    def smallestTrimmedNumbers(self, nums, queries):
        res = []
        for k, t in queries:
            idx = list(range(len(nums)))
            idx.sort(key=lambda i: (nums[i][-t:], i))
            res.append(idx[k - 1])
        return res

