var smallestTrimmedNumbers = function(nums, queries) {
    const res = [];
    for (const [k, t] of queries) {
        const idx = nums.map((_, i) => i);
        idx.sort((a, b) => {
            const sa = nums[a].slice(nums[a].length - t);
            const sb = nums[b].slice(nums[b].length - t);
            if (sa < sb) return -1;
            if (sa > sb) return 1;
            return a - b;
        });
        res.push(idx[k - 1]);
    }
    return res;
};
